import android.content.Context;
import android.content.SharedPreferences;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.util.Base64;
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.IvParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;

public class SecureLoginManager {
    private static final String PREF_NAME = "login_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_TOKEN = "token";
    private static final String KEY_IV = "iv";
    private static final String ANDROID_KEYSTORE = "AndroidKeyStore";
    private static final String KEY_ALIAS = "login_key";
    private static final String CIPHER_TRANSFORMATION = "AES/GCM/NoPadding";
    
    private Context context;
    private SharedPreferences prefs;
    private SecretKey secretKey;

    public SecureLoginManager(Context context) {
        this.context = context;
        this.prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        this.secretKey = getOrCreateSecretKey();
    }

    private SecretKey getOrCreateSecretKey() {
        try {
            android.security.keystore.KeyGenParameterSpec spec = new KeyGenParameterSpec.Builder(
                    KEY_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setRandomizedEncryptionRequired(false)
                    .build();
            
            KeyGenerator keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);
            keyGenerator.init(spec);
            return keyGenerator.generateKey();
        } catch (Exception e) {
            throw new RuntimeException("Failed to generate key", e);
        }
    }

    public void saveCredentials(String email, String token) {
        try {
            String encryptedEmail = encryptData(email);
            String encryptedToken = encryptData(token);
            
            SharedPreferences.Editor editor = prefs.edit();
            editor.putString(KEY_EMAIL, encryptedEmail);
            editor.putString(KEY_TOKEN, encryptedToken);
            editor.apply();
        } catch (Exception e) {
            throw new RuntimeException("Failed to save credentials", e);
        }
    }

    public LoginData getSavedCredentials() {
        String encryptedEmail = prefs.getString(KEY_EMAIL, null);
        String encryptedToken = prefs.getString(KEY_TOKEN, null);
        
        if (encryptedEmail == null || encryptedToken == null) {
            return null;
        }
        
        try {
            String email = decryptData(encryptedEmail);
            String token = decryptData(encryptedToken);
            return new LoginData(email, token);
        } catch (Exception e) {
            return null;
        }
    }

    public void clearCredentials() {
        SharedPreferences.Editor editor = prefs.edit();
        editor.remove(KEY_EMAIL);
        editor.remove(KEY_TOKEN);
        editor.apply();
    }

    private String encryptData(String data) throws Exception {
        Cipher cipher = Cipher.getInstance(CIPHER_TRANSFORMATION);
        cipher.init(Cipher.ENCRYPT_MODE, secretKey);
        
        byte[] encrypted = cipher.doFinal(data.getBytes());
        byte[] iv = cipher.getIV();
        
        String ivBase64 = Base64.encodeToString(iv, Base64.DEFAULT);
        String encryptedBase64 = Base64.encodeToString(encrypted, Base64.DEFAULT);
        
        return ivBase64 + ":" + encryptedBase64;
    }

    private String decryptData(String encryptedData) throws Exception {
        String[] parts = encryptedData.split(":", 2);
        byte[] iv = Base64.decode(parts[0], Base64.DEFAULT);
        byte[] encrypted = Base64.decode(parts[1], Base64.DEFAULT);
        
        Cipher cipher = Cipher.getInstance(CIPHER_TRANSFORMATION);
        IvParameterSpec ivSpec = new IvParameterSpec(iv);
        cipher.init(Cipher.DECRYPT_MODE, secretKey, ivSpec);
        
        byte[] decrypted = cipher.doFinal(encrypted);
        return new String(decrypted);
    }

    public static class LoginData {
        private String email;
        private String token;

        public LoginData(String email, String token) {
            this.email = email;
            this.token = token;
        }

        public String getEmail() {
            return email;
        }

        public String getToken() {
            return token;
        }
    }
}